package org.eclipse.rdf4j.query.algebra.evaluation.util;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.Set;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.And;
import org.eclipse.rdf4j.query.algebra.Bound;
import org.eclipse.rdf4j.query.algebra.Compare;
import org.eclipse.rdf4j.query.algebra.Extension;
import org.eclipse.rdf4j.query.algebra.ExtensionElem;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.Not;
import org.eclipse.rdf4j.query.algebra.Or;
import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

/**
 * Binding-injection safety is a JOINT property of the injected variable set. The canonical counterexample:
 * {@code FILTER(!BOUND(?x) || !BOUND(?y))} evaluated independently succeeds (both unbound); injecting only {@code ?x}
 * or only {@code ?y} still succeeds (the other disjunct holds); injecting BOTH fails the filter. So {?x} and {?y} are
 * each individually safe while {?x,?y} is not — an analysis that unions per-variable answers is unsound. The
 * conservative analyzer must therefore never authorize the joint set, and callers must always ask about the exact set
 * they intend to inject.
 */
public class BindingInjectionSafetyTest {

	private static StatementPattern pattern(String s, String p, String o) {
		return new StatementPattern(Var.of(s), Var.of(p), Var.of(o));
	}

	@Test
	public void jointBoundFilterIsNotInjectable() {
		Filter filter = new Filter(new SingletonSet(),
				new Or(new Not(new Bound(Var.of("x"))), new Not(new Bound(Var.of("y")))));

		assertFalse(QueryEvaluationUtility.permitsBindingInjection(filter, Set.of("x", "y")),
				"an expression observing the BOUND-ness of injected names can distinguish injection from independent evaluation");
		// The conservative analyzer also rejects the individually-safe singleton sets; that is sound
		// (a rejection is never a semantic claim) and keeps the joint contract impossible to misuse.
		assertFalse(QueryEvaluationUtility.permitsBindingInjection(filter, Set.of("x")));
		assertFalse(QueryEvaluationUtility.permitsBindingInjection(filter, Set.of("y")));
	}

	@Test
	public void extensionTargetCollisionIsNotInjectable() {
		// Extend is undefined when its target variable is already bound in the incoming mapping, and RDF4J's
		// evaluation would overwrite the injected value — the FilterInValues witness shape.
		Extension extension = new Extension(new SingletonSet(),
				new ExtensionElem(new ValueConstant(SimpleValueFactory.getInstance().createIRI("urn:a")), "x"));

		assertFalse(QueryEvaluationUtility.permitsBindingInjection(extension, Set.of("x")));
		assertTrue(QueryEvaluationUtility.permitsBindingInjection(extension, Set.of("unrelated")),
				"injecting a name the extension neither targets nor reads is a plain selection");
	}

	@Test
	public void expressionReadingInjectedNameIsNotInjectable() {
		Filter filter = new Filter(pattern("a", "p", "b"),
				new Compare(Var.of("outer"), new ValueConstant(SimpleValueFactory.getInstance().createLiteral(5)),
						Compare.CompareOp.GT));

		assertFalse(QueryEvaluationUtility.permitsBindingInjection(filter, Set.of("outer")),
				"independent evaluation sees ?outer unbound (condition errors, right is empty); injection would see a value");
		assertTrue(QueryEvaluationUtility.permitsBindingInjection(filter, Set.of("a")),
				"pattern-variable injection plus a filter over internally produced names is a selection");
	}

	@Test
	public void positivePatternShapesAreInjectable() {
		Join bgp = new Join(pattern("a", "p", "b"), pattern("b", "q", "c"));

		assertTrue(QueryEvaluationUtility.permitsBindingInjection(bgp, Set.of("a", "b", "c")));

		Filter filtered = new Filter(bgp.clone(),
				new And(new Bound(Var.of("b")),
						new Compare(Var.of("c"),
								new ValueConstant(SimpleValueFactory.getInstance().createLiteral(1)),
								Compare.CompareOp.GT)));
		assertTrue(QueryEvaluationUtility.permitsBindingInjection(filtered, Set.of("a")),
				"expressions over names the subtree itself produces do not observe the injection");
		assertFalse(QueryEvaluationUtility.permitsBindingInjection(filtered, Set.of("a", "b")),
				"?b is read by BOUND, so injecting it becomes observable");
	}

	@Test
	public void unknownOperatorsAreNotInjectable() {
		org.eclipse.rdf4j.query.algebra.TupleFunctionCall call = new org.eclipse.rdf4j.query.algebra.TupleFunctionCall();
		call.setURI("urn:test:tuple-function");

		assertFalse(QueryEvaluationUtility.permitsBindingInjection(call, Set.of("x")));
	}
}
